(508, 10, 'website-developing-meeting-october-27', 'اجتماع تطوير الموقع 27 اكتوبر', 'Website Developing Meeting October 27', 'عقد اجتماع خاص بتطوير موقع نيوإيجيبت مع مجموعة من المطورين و المصممين و ذلك لمناقشة أحدث التطورات في الموقع و بحث الأفكار المقترحه . كما سوف يتناول الإجتماع مناقشة و بحث كل تطوير و تحديث يساهم في جعل الموقع اسهل إستخداما للزائرين', 'A meeting will be held to discuss the development of the New Egypt website. Developers and designers will attend to talk about the latest developments on the site and what changes need to be made. The meeting will also cover how easy the website is to use for visitors.', NULL, '2022-10-27', '2022-10-27', '11:00:00', '12:30:00', 7, 2, 1, 0, 0, 40.7127753, -74.0059728, 'New York, NY, USA', '2022-10-27 13:24:26', '2022-10-27 13:24:26', NULL, 'عقد اجتماع خاص بتطوير موقع نيوإيجيبت مع مجموعة من المطورين', 'A meeting will be held to discuss the development of the New Egypt website', 'لمناقشة أحدث التطورات في الموقع و بحث الأفكار المقترحه . كما سوف يتناول الإجتماع مناقشة و بحث كل تطوير و تحديث يساهم في جعل', 'Developers and designers will attend to talk about the latest developments on the site and what changes need to be made', '4acc0b0d8c0997f366451b735f520755.png', NULL, 0, 'never', NULL, NULL, NULL, 0),
(509, 10, 'website-developing-meeting-november-14', 'اجتماع تطوير الموقع14 نوفمبر', 'Website Developing Meeting November 14', 'عقد اجتماع خاص بتطوير موقع نيوإيجيبت مع مجموعة من المطورين و المصممين و ذلك لمناقشة أحدث التطورات في الموقع و بحث الأفكار المقترحه . كما سوف يتناول الإجتماع مناقشة و بحث كل تطوير و تحديث يساهم في جعل الموقع اسهل إستخداما للزائرين', 'A meeting will be held to discuss the development of the New Egypt website. Developers and designers will attend to talk about the latest developments on the site and what changes need to be made. The meeting will also cover how easy the website is to use for visitors.', NULL, '2022-11-14', '2022-11-14', '12:30:00', '13:00:00', 7, 2, 1, 0, 0, 40.7127753, -74.0059728, 'New York, NY, USA', '2022-11-13 14:09:20', '2022-11-13 14:09:20', NULL, 'عقد اجتماع خاص بتطوير موقع نيوإيجيبت مع مجموعة من المطورين', 'A meeting will be held to discuss the development of the New Egypt website', 'لمناقشة أحدث التطورات في الموقع و بحث الأفكار المقترحه . كما سوف يتناول الإجتماع مناقشة و بحث كل تطوير و تحديث يساهم في جعل', 'Developers and designers will attend to talk about the latest developments on the site and what changes need to be made', '54b69c9842bd5349f1a08b175124f6ae.jpg', NULL, 0, 'never', NULL, NULL, NULL, 0),
(510, 10, 'website-developing-meeting-november-16', 'اجتماع تطوير و تحديث الموقع 16 نوفمبر', 'Website Developing Meeting November 16', 'عقد اجتماع خاص بتطوير موقع نيوإيجيبت مع مجموعة من المطورين و المصممين و ذلك لمناقشة أحدث التطورات في الموقع و بحث الأفكار المقترحه . كما سوف يتناول الإجتماع مناقشة و بحث كل تطوير و تحديث يساهم في جعل الموقع اسهل إستخداما للزائرين', 'A meeting will be held to discuss the development of the New Egypt website. Developers and designers will attend to talk about the latest developments on the site and what changes need to be made. The meeting will also cover how easy the website is to use for visitors.', NULL, '2022-11-16', '2022-11-16', '12:30:00', '13:59:00', 9, 2, 1, 0, 0, 40.7127753, -74.0059728, 'New York, NY, USA', '2022-11-13 14:19:53', '2022-11-22 13:41:39', NULL, 'عقد اجتماع خاص بتطويرو تحديث موقع نيوإيجيبت مع مجموعة من المطورين', 'A meeting will be held to discuss the development of the New Egypt website', 'لمناقشة أحدث التطورات في الموقع و بحث الأفكار المقترحه . كما سوف يتناول الإجتماع مناقشة و بحث كل تطوير و تحديث يساهم في جعل', 'Developers and designers will attend to talk about the latest developments on the site and what changes need to be made', '7c5efd55185bf1b8d4aa8bdcb3bef0ab.jpg', 0, 0, 'never', NULL, NULL, NULL, 0),
